long long solve(vector<vector<long long>> points) {
    const long long MOD = 1e9 + 7;
    map<long long, map<long long, int>> y_to_x_count;
    for (auto& p : points) {
        y_to_x_count[p[1]][p[0]]++;
    }

    long long result = 0;

    for (auto& y_pair : y_to_x_count) {
        long long y = y_pair.first;
        map<long long, int>& x_count = y_pair.second;
